package hw05.model.interactStrategies;

import java.awt.Color;
import java.awt.Point;
import java.awt.Rectangle;

import hw05.model.Ball;
import hw05.model.IBall;
import hw05.model.IBallAlgo;
import hw05.model.IBallCmd;
import hw05.model.updateStrategies.MultiStrategy;
import provided.utils.dispatcher.IDispatcher;
import provided.utils.dispatcher.IObserver;
import provided.utils.valueGenerator.impl.Randomizer;

/**
 * The interact strategy that generates a new ball with the average radius and color of the two balls that interacted
 *
 */
public class ReproduceStrategy implements IInteractStrategy {

	/**
	 * Generates a new ball with the average radius and color of the two balls that interacted
	 */
	public IBallCmd interactWith(IBall context, IBall target, IDispatcher<IBallCmd> disp) {
		int newRadius = (context.getRadius() + target.getRadius()) / 2;
		Color c1 = context.getColor();
		Color c2 = target.getColor();
		Color newColor = new Color((c1.getRed() + c2.getRed()) / 2, (c1.getGreen() + c2.getGreen()) / 2, (c1.getBlue() + c2.getBlue()) / 2);
		Point l1 = context.getLocation();
		Point l2 = target.getLocation();
		Point newLocation = new Point((l1.x + l2.x) / 2, (l1.y + l2.y) / 2);

		// Random velocity
		Point newVelocity = Randomizer.Singleton.randomVel(new Rectangle(25, 25, 25, 25));

		IBall offspring = new Ball(newLocation, newVelocity, newColor, newRadius, context.getDimension(), context.getCanvas(), new IBallAlgo() {
			@Override
			public void caseDefault(IBall host) {
				host.setUpdateStrategy(new MultiStrategy(context.getUpdateStrategy(), target.getUpdateStrategy()));
				host.setPaintStrategy(context.getPaintStrategy());
				host.setInteractStrategy(context.getInteractStrategy());
			}
		});

		disp.addObserver((IObserver<IBallCmd>) offspring);

		return (ball, d) -> {};
	}

	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

}

package hw05.model.interactStrategies;

import java.awt.Point;
import java.awt.geom.Point2D;

import hw05.model.IBall;
import hw05.model.IBallCmd;
import provided.utils.dispatcher.IDispatcher;

/**
 * @author cindy
 * Elastic Collision without decomposition
 *
 */
public class CollideStrategy implements  IInteractStrategy {

	@Override
	public IBallCmd interactWith(IBall source, IBall target, IDispatcher<IBallCmd> disp) {
		Point lSource = source.getLocation();
		Point lTarget = target.getLocation();
		double distance = lSource.distance(lTarget);
		double minSeparation = source.getRadius() + target.getRadius();

		if (distance < minSeparation) {
			double mSource = source.getRadius() * source.getRadius();
			double mTarget = target.getRadius() * target.getRadius();
			double rMass = reducedMass(mSource, mTarget);

			Point2D.Double normalVec = calcUnitVec(lSource, lTarget, distance);

			// Check if balls are approaching each other
			double vRelN = (target.getVelocity().x - source.getVelocity().x) * normalVec.x + 
			               (target.getVelocity().y - source.getVelocity().y) * normalVec.y;

			if (vRelN < 0) {
				Point2D.Double impulseVec = impulse(normalVec, source.getVelocity(), target.getVelocity(), rMass);
				updateVelocity(source, mSource, impulseVec);

				Point2D.Double impulseVecTarget = new Point2D.Double(-impulseVec.x, -impulseVec.y);
				updateVelocity(target, mTarget, impulseVecTarget);
			}

			Point nudge = calcNudgeVec(normalVec, minSeparation, distance);
			source.getLocation().translate(nudge.x, nudge.y);
			target.getLocation().translate(-nudge.x, -nudge.y);
		}

		return (context, d) -> {};
	}

	/**
	 * Returns the reduced mass of the two balls (m1*m2)/(m1+m2) Gives correct
	 * result if one of the balls has infinite mass.
	 * 
	 * @param mSource
	 *            Mass of the source ball
	 * @param mTarget
	 *            Mass of the target ball
	 * @return The reduced mass of the two balls
	 */
	protected double reducedMass(double mSource, double mTarget) {
		if (mSource == Double.POSITIVE_INFINITY) return mTarget;
		if (mTarget == Double.POSITIVE_INFINITY) return mSource;
		return (mSource * mTarget) / (mSource + mTarget);
	}

	Point2D.Double calcUnitVec(Point lSource, Point lTarget, double distance) {
		return new Point2D.Double((lTarget.x - lSource.x) / distance, (lTarget.y - lSource.y) / distance);
	}		

	protected Point2D.Double impulse(Point2D.Double normalVec, Point vSource, Point vTarget, double reducedMass) {
		double vRelN = (vTarget.x - vSource.x) * normalVec.x + (vTarget.y - vSource.y) * normalVec.y;
		double impulseMag = 2.0 * reducedMass * vRelN;
		return new Point2D.Double(impulseMag * normalVec.x, impulseMag * normalVec.y);
	}

	private static final double NudgeFactor = 1.1;

	Point calcNudgeVec(Point2D.Double normalVec, double minSeparation, double distance) {
		double nudgeMag = (minSeparation * NudgeFactor - distance) / 2.0;
		return new Point((int) Math.round(-nudgeMag * normalVec.x), (int) Math.round(-nudgeMag * normalVec.y));
	}

	protected void updateVelocity(IBall aBall, double mass, Point2D.Double impulseVec) {
		Point v = aBall.getVelocity();
		aBall.setVelocity(new Point((int) Math.round(v.x + impulseVec.x / mass), (int) Math.round(v.y + impulseVec.y / mass)));
	}

	@Override
	public void init(IBall context) {
		// TODO Auto-generated method stub

	}

	// Utilities for calculating reduced mass, unit vector, impuylse and nudge vector elided.

}

